'',
'    FOR i IN 1 .. l_roles.COUNT LOOP',
'        APEX_ACL.ADD_USER_ROLE (',
'            p_application_id => :APP_ID,',
'            p_user_name      => :P3_USER_NAME,',
'            p_role_static_id => UPPER(TRIM(l_roles(i)))',
'        );',
'    END LOOP;',
'',
'EXCEPTION',
'    WHEN OTHERS THEN',
'        RAISE_APPLICATION_ERROR(-20001, SQLERRM);',
'END;',
'',
''))
