wwv_flow_imp_page.create_page_validation(
 p_id=>wwv_flow_imp.id(160988411981843042)
,p_validation_name=>'No Duplicate In Database'
,p_validation_sequence=>20
,p_validation=>wwv_flow_string.join(wwv_flow_t_varchar2(
'WITH parsed AS (',
'  SELECT',
'    p.*,',
'    ROW_NUMBER() OVER (ORDER BY NULL) AS rn',
'  FROM apex_application_temp_files f',
'  CROSS JOIN TABLE(',
'    apex_data_parser.parse(',
'      p_content         => f.blob_content,',
'      p_file_name       => f.filename,',
'      p_skip_rows       => 1,',
'      p_xlsx_sheet_name => :P8_XLSX_WORKSHEET,',
'      p_file_profile    => apex_data_loading.get_file_profile(',
'                             p_static_id => ''load_staging_barcode''',
'                           )',
'    )',
'  ) p',
'  WHERE f.name = :P8_FILE',
'),',
'data_rows AS (',
'  SELECT',
'    UPPER(col001) AS mat_form,',
'    UPPER(col002) AS company_code,',
'    UPPER(col003) AS bucket,',
'    UPPER(col004) AS origin,',
'    UPPER(col005) AS specific_origin,',
'    UPPER(col006) AS quality,',
'    UPPER(col007) AS supplier,',
'    UPPER(col008) AS crop_year,',
'    UPPER(col009) AS additional_information,',
'    TO_NUMBER(col010)        AS batch_no,',
'    col011        AS gross,',
'    col012        AS tare,',
'    col013        AS net,',
'    col014        AS total_barcode',
'',
'  FROM parsed',
'  WHERE rn > 1',
')',
'SELECT u.*',
'FROM data_rows u',
'WHERE EXISTS (',
'  SELECT 1',
'  FROM xtd_kdk_lp_staging_barcode s',
'  WHERE s.mat_form        = u.mat_form',
'    AND s.company_code    = u.company_code',
'    AND s.bucket          = u.bucket',
'    AND s.origin          = u.origin',
'    AND s.specific_origin = u.specific_origin',
'    AND s.quality         = u.quality ',
'    AND s.supplier        = u.supplier',
'    AND s.crop_year       = u.crop_year',
'    AND NVL(s.additional_information, ''#'') = NVL(u.additional_information, ''#'')',
'    AND s.batch_no        = u.batch_no',
'    AND s.prefix_barcode IS NULL',
');'))
,p_validation_type=>'NOT_EXISTS'
,p_error_message=>'Data yang akan diupload ada yang sudah didatabase'
,p_when_button_pressed=>wwv_flow_imp.id(160886492818390898)
,p_error_display_location=>'INLINE_WITH_FIELD_AND_NOTIFICATION'
);
wwv_flow_imp_page.create_page_validation(
 p_id=>wwv_flow_imp.id(161216838863172561)
,p_validation_name=>'No Duplicate Batch No'
,p_validation_sequence=>30
,p_validation=>wwv_flow_string.join(wwv_flow_t_varchar2(
'WITH parsed AS (',
'  SELECT',
'    p.*,',
'    ROW_NUMBER() OVER (ORDER BY NULL) AS rn',
'  FROM apex_application_temp_files f',
'  CROSS JOIN TABLE(',
'    apex_data_parser.parse(',
'      p_content         => f.blob_content,',
'      p_file_name       => f.filename,',
'      p_skip_rows       => 1,',
'      p_xlsx_sheet_name => :P8_XLSX_WORKSHEET,',
'      p_file_profile    => apex_data_loading.get_file_profile(',
'                             p_static_id => ''load_staging_barcode''',
'                           )',
'    )',
'  ) p',
'  WHERE f.name = :P8_FILE',
'),',
'data_rows AS (',
'  SELECT',
'    UPPER(col001) AS mat_form,',
'    UPPER(col002) AS company_code,',
'    UPPER(col003) AS bucket,',
'    UPPER(col004) AS origin,',
'    UPPER(col005) AS specific_origin,',
'    UPPER(col006) AS quality,',
'    UPPER(col007) AS supplier,',
'    UPPER(col008) AS crop_year,',
'    UPPER(col009) AS additional_information,',
'    TO_NUMBER(col010)        AS batch_no,',
'    col011        AS gross,',
'    col012        AS tare,',
'    col013        AS net,',
'    col014        AS total_barcode',
'',
'  FROM parsed',
'  WHERE rn > 1',
')',
'SELECT',
'    mat_form,',
