 p_id=>wwv_flow_imp.id(160873533643355065)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'INSERT Batch'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'INSERT INTO xtd_kdk_lp_staging_barcode (',
'  mat_form,',
'  company_code,',
'  bucket,',
'  origin,',
'  specific_origin,',
'  quality,',
'  supplier,',
'  crop_year,',
'  additional_information,',
'  batch_no,',
'  gross,',
'  tare,',
'  net,',
'  total_barcode,',
'  start_running_number,',
'  end_running_number,',
'  created_by,',
'  created_date',
')',
'WITH parsed AS (',
'  SELECT',
'    p.*,',
'    ROW_NUMBER() OVER (ORDER BY NULL) AS rn',
'  FROM apex_application_temp_files f',
'  CROSS JOIN TABLE(',
'    apex_data_parser.parse(',
'      p_content         => f.blob_content,',
'      p_file_name       => f.filename,',
'      p_skip_rows       => 1,',
'      p_xlsx_sheet_name => :P8_XLSX_WORKSHEET,',
'      p_file_profile    => apex_data_loading.get_file_profile(',
'                             p_static_id => ''load_staging_barcode''',
'                           )',
'    )',
'  ) p',
'  WHERE f.name = :P8_FILE',
'),',
'data_rows AS (',
'  SELECT',
'    UPPER(col001) AS mat_form,',
'    UPPER(col002) AS company_code,',
'    UPPER(col003) AS bucket,',
'    UPPER(col004) AS origin,',
'    UPPER(col005) AS specific_origin,',
'    UPPER(col006) AS quality,',
'    UPPER(col007) AS supplier,',
'    UPPER(col008) AS crop_year,',
'    UPPER(col009) AS additional_information,',
'    TO_NUMBER(col010)        AS batch_no,',
'    col011        AS gross,',
'    col012        AS tare,',
'    col013        AS net,',
'    col014        AS total_barcode',
'',
'  FROM parsed',
'  WHERE rn > 1',
'),',
'existing_totals AS (',
'  SELECT',
'    mat_form,',
'    company_code,',
'    bucket,',
'    origin,',
'    specific_origin,',
'    quality,',
'    supplier,',
'    crop_year,',
'    additional_information,',
'    SUM(TOTAL_BARCODE) AS TOTAL_EXISTING',
'  FROM xtd_kdk_lp_staging_barcode',
'  GROUP BY',
'    mat_form,',
'    company_code,',
'    bucket,',
'    origin,',
'    specific_origin,',
'    quality,',
'    supplier,',
'    crop_year,',
'    additional_information',
'),',
'numbered AS (',
'  SELECT',
'    d.*,',
'    NVL(e.total_existing, 0)',
'    +',
'    NVL(',
'      SUM(d.total_barcode) OVER (',
'        PARTITION BY',
'          d.company_code,',
'          d.specific_origin,',
'          d.supplier,',
'          d.crop_year',
'        ORDER BY d.batch_no',
'        ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING',
'      ),',
'      0',
'    )',
'    + 1 AS start_running_number',
'  FROM data_rows d',
'  LEFT JOIN existing_totals e',
'    ON  d.mat_form               = e.mat_form',
'    AND d.company_code           = e.company_code',
'    AND d.bucket                 = e.bucket',
'    AND d.origin                 = e.origin',
'    AND d.specific_origin        = e.specific_origin',
'    AND d.quality                = e.quality',
'    AND d.supplier               = e.supplier',
'    AND d.crop_year              = e.crop_year',
'    AND d.additional_information = e.additional_information',
')',
'SELECT',
'  mat_form,',
'  company_code,',
'  bucket,',
'  origin,',
'  specific_origin,',
'  quality,',
'  supplier,',
'  crop_year,',
'  additional_information,',
'  batch_no,',
'  gross,',
'  tare,',
'  net,',
'  total_barcode,',
'  start_running_number,',
'  start_running_number + total_barcode - 1 AS end_running_number,',
'  :APP_USER,',
'  CURRENT_TIMESTAMP',
'FROM numbered;',
''))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(160886492818390898)
,p_internal_uid=>11472137126917045
);
