'SELECT',
'    BC.ID,',
'    BC.ID AS EDIT,',
'    SBC.MAT_FORM,',
'    SBC.COMPANY_CODE,',
'    SBC.BUCKET,',
'    SBC.ORIGIN,',
'    SBC.SPECIFIC_ORIGIN,',
