prompt --application/deployment/install/install_function
begin
wwv_flow_imp_shared.create_install_script(
 p_id=>wwv_flow_imp.id(170673867569419945)
,p_install_id=>wwv_flow_imp.id(160840780812216643)
,p_name=>'function'
,p_sequence=>110
,p_script_type=>'INSTALL'
,p_script_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'create or replace FUNCTION arrange_barcode (',
'    p_id IN NUMBER,',
'    p_is_2024 IN BOOLEAN DEFAULT FALSE',
') RETURN VARCHAR2',
'IS',
'    -- record untuk staging barcode',
'    TYPE r_bc IS RECORD (',
'        company_code           VARCHAR2(10),',
'        mat_form               VARCHAR2(10),',
'        specific_origin        VARCHAR2(10),',
'        crop_year              VARCHAR2(10),',
'        quality                VARCHAR2(10),',
'        supplier               VARCHAR2(10),',
'        additional_information VARCHAR2(10),',
'        running_number         NUMBER,',
'        prefix_barcode         VARCHAR2(21)',
'    );',
'',
'    v_bc r_bc;',
'',
'    -- hasil mapping',
'    v_company_code           VARCHAR2(2);',
'    v_mat_form               VARCHAR2(2);',
'    v_specific_origin        VARCHAR2(2);',
'    v_quality                VARCHAR2(2);',
'    v_supplier               VARCHAR2(2);',
'    v_additional_information VARCHAR2(2);',
'',
'BEGIN',
'    /* ambil data utama */',
'    SELECT',
'        sbc.company_code,',
'        sbc.mat_form,',
'        sbc.specific_origin,',
'        sbc.crop_year,',
'        sbc.quality,',
'        sbc.supplier,',
'        sbc.additional_information,',
'        bc.running_number,',
'        sbc.prefix_barcode',
'    INTO v_bc',
'    FROM xtd_kdk_lp_staging_barcode sbc',
'    JOIN xtd_kdk_lp_barcode bc',
'        ON bc.xtd_kdk_lp_staging_barcode_id = sbc.id',
'    WHERE bc.id = p_id;',
'',
'    IF p_is_2024 = FALSE THEN',
'        /* mapping serial -> number */',
'        SELECT',
'            MAX(CASE WHEN content = ''COMPANY CODE''              AND serial = v_bc.company_code THEN LPAD(number_code, 2, ''0'') END) AS company_code,',
'            MAX(CASE WHEN content = ''SPECIFIC ORIGIN''           AND serial = v_bc.specific_origin THEN LPAD(number_code, 2, 0) END) AS specific_origin,',
'            MAX(CASE WHEN content = ''MAT FORM''                  AND serial = v_bc.mat_form THEN LPAD(number_code, 2, ''0'') END) AS mat_form,',
'            MAX(CASE WHEN content = ''QUALITY (AB TEST)''         AND serial = v_bc.quality THEN number_code END) AS quality,',
'            MAX(CASE WHEN content = ''ADDITIONAL INFORMATION''    AND serial = v_bc.additional_information THEN LPAD(number_code, 2, ''0'') END) AS additional_information,',
'            MAX(CASE WHEN content IN (''SUPPLIER'', ''OPKOPER'')                  AND serial = v_bc.supplier THEN LPAD(number_code, 2, ''0'') END) AS supplier',
'        INTO',
'            v_company_code,',
'            v_specific_origin,',
'            v_mat_form,',
'            v_quality,',
'            v_additional_information,',
'            v_supplier',
'        FROM xtd_kdk_master_serial_barcode;',
'',
'        RETURN',
'              v_company_code',
'            || v_mat_form',
'            || v_specific_origin',
'            || v_bc.crop_year',
'            || v_quality',
'            || v_supplier',
'            || v_additional_information',
'            || LPAD(v_bc.running_number, 5, ''0'');',
'    ELSE',
'        RETURN v_bc.prefix_barcode || LPAD(v_bc.running_number, 8, ''0'');',
'    ',
'    END IF;',
'',
'EXCEPTION',
'    WHEN NO_DATA_FOUND THEN',
'        RETURN NULL;',
'END arrange_barcode;',
'/',
'create or replace FUNCTION is_transient_error(p_code NUMBER) RETURN BOOLEAN',
'as',
'begin',
'    return p_code in (-54, -60, -2049);',
'end "IS_TRANSIENT_ERROR";',
'/ '))
);
wwv_flow_imp_shared.create_install_object(
 p_id=>wwv_flow_imp.id(170673948307419945)
,p_script_id=>wwv_flow_imp.id(170673867569419945)
,p_object_owner=>'#OWNER#'
,p_object_type=>'FUNCTION'
,p_object_name=>'ARRANGE_BARCODE'
);
wwv_flow_imp_shared.create_install_object(
 p_id=>wwv_flow_imp.id(170674152272419945)
,p_script_id=>wwv_flow_imp.id(170673867569419945)
,p_object_owner=>'#OWNER#'
,p_object_type=>'FUNCTION'
,p_object_name=>'IS_TRANSIENT_ERROR'
);
end;
/
prompt --application/deployment/install/install_procedure
begin
wwv_flow_imp_shared.create_install_script(
 p_id=>wwv_flow_imp.id(170674588508425355)
,p_install_id=>wwv_flow_imp.id(160840780812216643)
,p_name=>'procedure'
,p_sequence=>120
,p_script_type=>'INSTALL'
,p_script_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'create or replace PROCEDURE BARCODE_JOB_WORKER',
'IS',
'BEGIN',
'    MARK_FAILED_JOB_TO_ATTEMPT();',
'    PROCESS_KDK_LP_BARCODE_JOB();',
'',
'END;',
'/',
'create or replace PROCEDURE MARK_FAILED_JOB_TO_ATTEMPT',
'IS',
'BEGIN',
'    UPDATE XTD_KDK_LP_JOB',
'    SET status = ''ATTEMPT'',',
'        LAST_ATTEMPT_AT = CURRENT_TIMESTAMP',
'    WHERE status = ''FAILED''',
'      AND NVL(ATTEMPT_COUNT, 0) < NVL(MAX_ATTEMPT, 3)',
'      AND LAST_ATTEMPT_AT < CURRENT_TIMESTAMP - INTERVAL ''2'' MINUTE;',
'',
'    COMMIT;',
'    ',
'    UPDATE XTD_KDK_LP_STAGING_BARCODE',
'    SET status = ''ATTEMPT''',
'    WHERE xtd_kdk_lp_job_id IN (',
'        SELECT id ',
'        FROM xtd_kdk_lp_job',
'        WHERE status = ''ATTEMPT''',
'    );',
'',
'    COMMIT;',
'END;',
'/',
'create or replace PROCEDURE PROCESS_KDK_LP_BARCODE_JOB',
'IS',
'    v_job_id       XTD_KDK_LP_JOB.ID%TYPE;',
'    v_job_run_id   XTD_KDK_LP_JOB_RUN.ID%TYPE;',
'    v_payload      CLOB;',
'    v_dummy        NUMBER;',
'    v_error_msg    VARCHAR2(4000);',
'    ',
'    v_retry_count  NUMBER := 0;',
'    v_total_items NUMBER;',
'    ',
'    v_env VARCHAR2(40) := apex_app_setting.get_value(''APP_ENV'');',
'',
'    CURSOR c_job IS',
'        SELECT id, payload',
'        FROM XTD_KDK_LP_JOB',
'        WHERE status IN (''PENDING'', ''ATTEMPT'')',
'        ORDER BY created_date',
'        FOR UPDATE SKIP LOCKED;',
'',
'BEGIN',
'    ----------------------------------------------------------------',
'    -- 1. Ambil satu job',
'    ----------------------------------------------------------------',
'    OPEN c_job;',
'    FETCH c_job INTO v_job_id, v_payload;',
'',
'    IF c_job%NOTFOUND THEN',
'        CLOSE c_job;',
'        RETURN;',
'    END IF;',
'',
'    UPDATE XTD_KDK_LP_JOB',
'    SET status = ''IN_PROGRESS'',',
'        updated_date = CURRENT_TIMESTAMP',
'    WHERE CURRENT OF c_job;',
'',
'    CLOSE c_job;',
'',
'    ----------------------------------------------------------------',
'    -- 2. Buat JOB_RUN',
'    ----------------------------------------------------------------',
'    SELECT SUM(total_barcode)',
'    INTO v_total_items',
'    FROM xtd_kdk_lp_staging_barcode',
'    WHERE xtd_kdk_lp_job_id = v_job_id;',
'',
'    INSERT INTO XTD_KDK_LP_JOB_RUN (',
'        XTD_KDK_LP_JOB_ID,',
'        STATUS,',
'        START_AT,',
'        CREATED_DATE,',
'        TOTAL_ITEMS',
'    )',
'    VALUES (',
'        v_job_id,',
'        ''IN_PROGRESS'',',
'        CURRENT_TIMESTAMP,',
'        CURRENT_TIMESTAMP,',
'        v_total_items',
'    )',
'    RETURNING id INTO v_job_run_id;',
'',
'    COMMIT;',
'',
'    ----------------------------------------------------------------',
'    -- 3. Proses STAGING BARCODE',
'    ----------------------------------------------------------------',
'    FOR r_stg IN (',
'        SELECT s.*',
'        FROM XTD_KDK_LP_STAGING_BARCODE s',
'        WHERE s.id IN (',
'            SELECT jt.column_value',
'            FROM JSON_TABLE(',
'                v_payload,',
'                ''$.staging_ids[*]''',
'                COLUMNS (column_value NUMBER PATH ''$'')',
'            ) jt',
'        )',
'        AND s.status IN (''QUEUED'', ''ATTEMPT'')',
'        ORDER BY s.id',
'    )',
'    LOOP',
'        <<retry_row>>',
'        BEGIN',
'            ------------------------------------------------------------',
'            -- 3a. Tandai IN_PROGRESS',
'            ------------------------------------------------------------',
'            UPDATE XTD_KDK_LP_STAGING_BARCODE',
'            SET status = ''IN PROGRESS'',',
'                updated_date = CURRENT_TIMESTAMP',
'            WHERE id = r_stg.id;',
'',
'            COMMIT;',
'',
'            IF v_env = ''DEVELOPMENT'' THEN',
'                DBMS_SESSION.SLEEP(15);',
'            END IF;',
'',
'            ------------------------------------------------------------',
'            -- 3b. Cek apakah barcode sudah ada',
'            ------------------------------------------------------------',
'            BEGIN',
'                SELECT 1',
'                INTO v_dummy',
'                FROM XTD_KDK_LP_BARCODE b',
'                WHERE b.XTD_KDK_LP_STAGING_BARCODE_ID = r_stg.id',
'                AND ROWNUM = 1;',
'',
'                -- Jika sampai sini, berarti barcode sudah ada',
'                UPDATE XTD_KDK_LP_STAGING_BARCODE',
'                SET status = ''FINISHED'',',
'                    updated_date = CURRENT_TIMESTAMP',
'                WHERE id = r_stg.id;',
'',
'                COMMIT;',
'                CONTINUE;',
'',
'            EXCEPTION',
'                WHEN NO_DATA_FOUND THEN',
'                    NULL; -- lanjut generate',
'            END;',
'',
'            ------------------------------------------------------------',
'            -- 3c. Generate barcode',
'            ------------------------------------------------------------',
'            FOR i IN r_stg.start_running_number .. r_stg.end_running_number',
'            LOOP',
'                INSERT INTO XTD_KDK_LP_BARCODE (',
'                    XTD_KDK_LP_STAGING_BARCODE_ID,',
'                    RUNNING_NUMBER,',
'                    CREATED_DATE,',
'                    GROSS,',
'                    TARE,',
'                    NET',
'                )',
'                VALUES (',
'                    r_stg.id,',
'                    i,',
'                    CURRENT_TIMESTAMP,',
'                    r_stg.gross,',
'                    r_stg.tare,',
'                    r_stg.net',
'                );',
'            END LOOP;',
'',
'            ------------------------------------------------------------',
'            -- 3d. Tandai FINISHED',
'            ------------------------------------------------------------',
'            UPDATE XTD_KDK_LP_STAGING_BARCODE',
'            SET status = ''FINISHED'',',
'                updated_date = CURRENT_TIMESTAMP',
'            WHERE id = r_stg.id;',
'',
'            UPDATE XTD_KDK_LP_JOB_RUN',
'            SET PROCESSED_ITEMS = NVL(PROCESSED_ITEMS, 0) + 1',
'            WHERE id = v_job_run_id;',
'',
'            COMMIT;',
'',
'        EXCEPTION',
'            WHEN OTHERS THEN',
'                v_error_msg := SQLERRM;',
'',
'                IF is_transient_error(SQLCODE)',
'                   AND v_retry_count < 3 THEN',
'',
'                    v_retry_count := v_retry_count + 1;',
'                    DBMS_SESSION.SLEEP(2);',
'                    GOTO retry_row;',
'',
'                ELSE',
'                    -- Mark menjadi Failed tabel staging',
'                    UPDATE XTD_KDK_LP_STAGING_BARCODE',
'                    SET status = ''FAILED'',',
'                        updated_date = CURRENT_TIMESTAMP',
'                    WHERE id = r_stg.id;',
'',
'                    COMMIT;',
'                END IF;',
'',
'                EXECUTE IMMEDIATE ''DELETE FROM xtd_kdk_lp_barcode WHERE xtd_kdk_lp_staging_barcode_id = '' || r_stg.id;',
'',
'                COMMIT;',
'        END;',
'    END LOOP;',
'',
'    ----------------------------------------------------------------',
'    -- 4. Job sukses',
'    ----------------------------------------------------------------',
'    SELECT COUNT(*)',
'    INTO v_dummy',
'    FROM XTD_KDK_LP_STAGING_BARCODE',
'    WHERE status = ''FAILED''',
'    AND id IN (',
'        SELECT jt.column_value',
'        FROM JSON_TABLE(',
'            v_payload,',
'            ''$.staging_ids[*]''',
'            COLUMNS (column_value NUMBER PATH ''$'')',
'        ) jt',
'    );',
'',
'    IF v_dummy > 0 THEN',
'        UPDATE XTD_KDK_LP_JOB',
'        SET STATUS = ''FAILED'',',
'            UPDATED_DATE = CURRENT_TIMESTAMP',
'        WHERE id = v_job_id;',
'',
'        UPDATE XTD_KDK_LP_JOB_RUN',
'        SET STATUS = ''FAILED'',',
'            FINSISHED_AT = CURRENT_TIMESTAMP',
'        WHERE id = v_job_run_id;',
'    ELSE',
'        UPDATE XTD_KDK_LP_JOB',
'        SET STATUS = ''FINISHED'',',
'            UPDATED_DATE = CURRENT_TIMESTAMP',
'        WHERE id = v_job_id;',
'',
'        UPDATE XTD_KDK_LP_JOB_RUN',
'        SET STATUS = ''FINISHED'',',
'            FINSISHED_AT = CURRENT_TIMESTAMP',
'        WHERE id = v_job_run_id;',
'    END IF;',
'',
'    COMMIT;',
'',
'END;',
'/',
'create or replace PROCEDURE RECOVER_STALE_STAGING',
'IS',
'BEGIN',
'    UPDATE XTD_KDK_LP_STAGING_BARCODE s',
'    SET s.status = ''FAILED'',',
'        s.updated_date = CURRENT_TIMESTAMP',
'    WHERE s.status = ''IN_PROGRESS''',
'      AND s.updated_date < CURRENT_TIMESTAMP - INTERVAL ''15'' MINUTE',
'      AND NOT EXISTS (',
'          SELECT 1',
'          FROM XTD_KDK_LP_JOB j',
'          WHERE j.id = s.XTD_KDK_LP_JOB_ID',
'            AND j.status = ''IN_PROGRESS''',
'      );',
'',
'    COMMIT;',
'END;',
'/ '))
);
wwv_flow_imp_shared.create_install_object(
 p_id=>wwv_flow_imp.id(170674638673425355)
,p_script_id=>wwv_flow_imp.id(170674588508425355)
,p_object_owner=>'#OWNER#'
,p_object_type=>'PROCEDURE'
,p_object_name=>'BARCODE_JOB_WORKER'
);
wwv_flow_imp_shared.create_install_object(
 p_id=>wwv_flow_imp.id(170674866503425355)
,p_script_id=>wwv_flow_imp.id(170674588508425355)
,p_object_owner=>'#OWNER#'
,p_object_type=>'PROCEDURE'
,p_object_name=>'MARK_FAILED_JOB_TO_ATTEMPT'
);
wwv_flow_imp_shared.create_install_object(
 p_id=>wwv_flow_imp.id(170675073891425355)
,p_script_id=>wwv_flow_imp.id(170674588508425355)
,p_object_owner=>'#OWNER#'
,p_object_type=>'PROCEDURE'
,p_object_name=>'PROCESS_KDK_LP_BARCODE_JOB'
);
wwv_flow_imp_shared.create_install_object(
 p_id=>wwv_flow_imp.id(170675230038425355)
,p_script_id=>wwv_flow_imp.id(170674588508425355)
,p_object_owner=>'#OWNER#'
,p_object_type=>'PROCEDURE'
,p_object_name=>'RECOVER_STALE_STAGING'
);
end;
/
prompt --application/deployment/install/install_view
begin
wwv_flow_imp_shared.create_install_script(
 p_id=>wwv_flow_imp.id(170675661379441602)
,p_install_id=>wwv_flow_imp.id(160840780812216643)
,p_name=>'view'
,p_sequence=>130
,p_script_type=>'INSTALL'
,p_script_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'  CREATE OR REPLACE FORCE EDITIONABLE VIEW "V_KDK_LP_BARCODE" ("BARCODE_ID", "ID", "MAT_FORM", "COMPANY_CODE", "BUCKET", "ORIGIN", "SPECIFIC_ORIGIN", "QUALITY", "SUPPLIER", "CROP_YEAR", "ADDITIONAL_INFORMATION", "BATCH_NO", "GROSS", "TARE", "NET", "T'
||'OTAL_BARCODE", "START_RUNNING_NUMBER", "END_RUNNING_NUMBER", "PREFIX_BARCODE", "CREATED_DATE", "CREATED_BY", "UPDATED_DATE", "UPDATED_BY", "XTD_KDK_LP_JOB_ID", "STATUS", "RUNNING_NUMBER", "BARCODE", "BARCODE_2024") AS ',
'  SELECT ',
'    bc."ID" AS BARCODE_ID,sbc."ID",sbc."MAT_FORM",sbc."COMPANY_CODE",sbc."BUCKET",sbc."ORIGIN",sbc."SPECIFIC_ORIGIN",sbc."QUALITY",sbc."SUPPLIER",sbc."CROP_YEAR",sbc."ADDITIONAL_INFORMATION",sbc."BATCH_NO",sbc."GROSS",sbc."TARE",sbc."NET",sbc."TOTAL_'
||'BARCODE",sbc."START_RUNNING_NUMBER",sbc."END_RUNNING_NUMBER",sbc."PREFIX_BARCODE",sbc."CREATED_DATE",sbc."CREATED_BY",sbc."UPDATED_DATE",sbc."UPDATED_BY",sbc."XTD_KDK_LP_JOB_ID",sbc."STATUS",',
'    bc.running_number,',
'    ARRANGE_BARCODE(bc.id) AS BARCODE,',
'    CASE ',
'        WHEN sbc.crop_year = ''24'' THEN ARRANGE_BARCODE(bc.id, TRUE)',
'        ELSE ''-''',
'    END AS BARCODE_2024',
'FROM xtd_kdk_lp_staging_barcode sbc',
'JOIN xtd_kdk_lp_barcode bc ON sbc.id = bc.xtd_kdk_lp_staging_barcode_id; '))
);
wwv_flow_imp_shared.create_install_object(
 p_id=>wwv_flow_imp.id(170675703075441602)
,p_script_id=>wwv_flow_imp.id(170675661379441602)
,p_object_owner=>'#OWNER#'
,p_object_type=>'VIEW'
,p_object_name=>'V_KDK_LP_BARCODE'
);
end;
